import{_ as e,c as t,o as a,d as r}from"./app.189ca219.js";const g=`{"title":"Packs","description":"","frontmatter":{"title":"Packs","sidebar":false},"headers":[{"level":2,"title":"UI Packs","slug":"ui-packs"},{"level":3,"title":"LeGend's Dark UI","slug":"legend-s-dark-ui"},{"level":3,"title":"LeGend's UI Pack","slug":"legend-s-ui-pack"},{"level":3,"title":"LeGend's Better UI","slug":"legend-s-better-ui"},{"level":3,"title":"F1 and F8 Buttons","slug":"f1-and-f8-buttons"},{"level":2,"title":"Add-Ons","slug":"add-ons"},{"level":3,"title":"More Recipes Add-On","slug":"more-recipes-add-on"}],"relativePath":"packs.md"}`,s={},o=r('<h1 id="packs" tabindex="-1">Packs <a class="header-anchor" href="#packs" aria-hidden="true">#</a></h1><div class="info custom-block"><p class="custom-block-title">INFO</p><p>All Packs shown below are available <a href="https://mcpedl.com/user/legend077" target="_blank" rel="noopener noreferrer">here</a>.</p></div><h2 id="ui-packs" tabindex="-1">UI Packs <a class="header-anchor" href="#ui-packs" aria-hidden="true">#</a></h2><h3 id="legend-s-dark-ui" tabindex="-1">LeGend&#39;s Dark UI <a class="header-anchor" href="#legend-s-dark-ui" aria-hidden="true">#</a></h3><p>Have you experienced any sort of thing that the Minecraft UI is light? I know you use Dark Mode on Websites, Youtube and Discord but not on Minecraft Bedrock. Here is LeGend&#39;s Dark UI which makes the UI Dark. Almost Every thing is dark in this pack. It is compatible with any other pack except UI pack. Using that with any other pack requires to put it on top of every pack.</p><p>Download it --&gt; <a href="https://mcpedl.com/legend-s-dark-ui/" target="_blank" rel="noopener noreferrer">Here</a>.</p><h3 id="legend-s-ui-pack" tabindex="-1">LeGend&#39;s UI Pack <a class="header-anchor" href="#legend-s-ui-pack" aria-hidden="true">#</a></h3><p>LeGend&#39;s UI Pack! It is a UI pack which makes the Vanilla UI better! It adds additional buttons, shortcuts which are toggle-able. It is not compatible with any other UI pack but works with any texture pack. It has a toggle panel. Note: Extra toggles and buttons are only for mobile players. PC players can have some advantage. Let&#39;s move to the details of the pack! It is better than my Old UI! You can try it as improves your gameplay a lot.</p><p>Our most popular pack!</p><p>Download it --&gt; <a href="https://mcpedl.com/legend-s-ui-pack/" target="_blank" rel="noopener noreferrer">Here</a></p><h3 id="legend-s-better-ui" tabindex="-1">LeGend&#39;s Better UI <a class="header-anchor" href="#legend-s-better-ui" aria-hidden="true">#</a></h3><p>LeGend&#39;s Better UI - It is a UI which makes the MCBE in-game UI better! It adds additional buttons, shortcuts and have choices between them! It is dark themed to support eyes! It is not compatible with any UI pack but can be used with texture packs. It has panel toggles.</p><ul><li>Extra Buttons and toggles is only for mobile players- PC players can have &#39;some&#39; features including UI Texture.</li></ul><p>Download it --&gt; <a href="https://mcpedl.com/legend-s-better-ui/" target="_blank" rel="noopener noreferrer">Here</a></p><h3 id="f1-and-f8-buttons" tabindex="-1">F1 and F8 Buttons <a class="header-anchor" href="#f1-and-f8-buttons" aria-hidden="true">#</a></h3><p>This is a simple pack which adds two buttons for mobile users i.e. F1 and F8 Buttons. A user suggested it to separate it from My UI Pack. So, here it is!</p><ul><li><p>F1 Button: Hides/Shows all the GUI like Moving buttons and Pause Buttons etc.</p></li><li><p>F8 Button: Hides/Shows the Paper doll in the left corner which is the small character in the top left.</p></li></ul><p>Download it --&gt; <a href="https://mcpedl.com/f1-and-f8-buttons/" target="_blank" rel="noopener noreferrer">Here</a></p><blockquote><p><strong>In Progress: None</strong></p></blockquote><h2 id="add-ons" tabindex="-1">Add-Ons <a class="header-anchor" href="#add-ons" aria-hidden="true">#</a></h2><h3 id="more-recipes-add-on" tabindex="-1">More Recipes Add-On <a class="header-anchor" href="#more-recipes-add-on" aria-hidden="true">#</a></h3><p>Do you ever feel that there is no recipe for saddle? Or for elytra or Totem of Undying? Here is the Add-On which adds so many recipes to the game! Inspired by Mysticat. My First Add-On \u{1F603}</p><p>Donwload it --&gt; <a href="https://mcpedl.com/more-recipes-add-on/" target="_blank" rel="noopener noreferrer">Here</a></p><blockquote><p><strong>In Progress: More Structures Add-On</strong></p></blockquote>',24),n=[o];function i(d,l,c,h,p,u){return a(),t("div",null,n)}var b=e(s,[["render",i]]);export{g as __pageData,b as default};
